export const CARDS_KENCHIKU = [
  { id: 42, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "こんばあじょん", jp: "コンバージョン", id_text: "Konversi bangunan", desc: "Memanfaatkan struktur bangunan yang sudah ada untuk diubah ke fungsi baru. Contoh: kantor → apartemen.", _origIndex: 40 },
  { id: 43, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "あとせこうあんかあ", jp: "あと施工アンカー", id_text: "Angkur pasca-cor", desc: "Angkur yang dipasang pada beton yang sudah mengeras. Ada 2 jenis: 金属系 (metal) dan 接着系 (adhesive/resin).", _origIndex: 41 },
  { id: 44, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "けいりょうてっこつじゅりょうてっこつ", jp: "軽量鉄骨（LGS） vs 重量鉄骨", id_text: "Baja ringan (LGS <6mm) vs baja berat (≥6mm)", desc: "Baja ringan (軽量鉄骨/LGS): tebal <6mm — untuk rangka dinding/plafon. Baja berat (重量鉄骨): ≥6mm — struktur utama gedung.", _origIndex: 42 },
  { id: 45, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "ぶれすらあめんとらす", jp: "鉄骨構造の種類（ブレース・ラーメン・トラス）", id_text: "Struktur baja: brace / ramen / truss", desc: "①ブレース: diagonal brace. ②ラーメン: rigid joint kolom-balok → tahan gempa. ③トラス: susunan segitiga → atap/jembatan.", _origIndex: 43 },
  { id: 46, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "たてにげすいへいつまげ", jp: "建て逃げ方式 vs 水平積み上げ方式", id_text: "Pemasangan baja: mobile crane vs tower crane", desc: "①建て逃げ: mobile crane, dari belakang ke depan. ②水平積み上げ: tower crane, lantai per lantai → gedung pencakar langit.", _origIndex: 44 },
  { id: 181, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "すいしんとんねる", jp: "推進トンネル（すいしんトンネル）", id_text: "Terowongan jack-push / pipe jacking", desc: "Pipa prefabrikasi (コンクリート管・ダクタイル管・鋼管) didorong masuk ke tanah oleh jack dari shaft peluncur. Digunakan untuk infrastruktur perkotaan seperti saluran air, gas, listrik, dan komunikasi.", _origIndex: 172 },
  { id: 186, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "けんちくぶつのこうぞうしゅるい", jp: "建築物の構造種類（RC・S・SRC・木造・CB造）", id_text: "Jenis struktur: RC, S, SRC, kayu, blok beton", desc: "RC造=tulangan+beton, S造=baja, SRC造=baja+RC (terkuat), 木造=kayu, CB造=blok beton. Mandor:「ここはS造だから溶接確認して」(ini S造, cek las).", _origIndex: 177 },
  { id: 188, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "やまどめこうじしほこう", jp: "山留め工事（やまどめ）・支保工（しほこう）", id_text: "Pekerjaan penahan tanah / shoring", desc: "Dinding sementara di dalam tanah untuk cegah longsor saat penggalian, diperkuat strutting (支保工). Mandor:「山留めの切梁確認して」(cek strut penahan tanah).", _origIndex: 179 },
  { id: 190, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "たいしんせいしんめんしん", jp: "耐震・制振・免振（たいしん・せいしん・めんしん）", id_text: "Tahan gempa / kontrol getaran / isolasi gempa", desc: "耐震 = kolom/balok dibuat kokoh untuk menahan guncangan. 制振 = damper dipasang di bangunan untuk menyerap energi getaran. 免振 = isolator + damper di fondasi agar energi gempa tidak tersalur ke bangunan.", _origIndex: 181 },
  { id: 198, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "てっきんつぎてこうじしゅるい", jp: "鉄筋継手工事の4種類（てっきんつぎて）", id_text: "4 metode penyambungan tulangan baja", desc: "①ガス圧接 = dipanaskan + ditekan (paling umum). ②溶接継手 = arc welding untuk diameter besar. ③機械式継手 = penyambung berulir (coupler). ④重ね接手 = ditumpuk lalu disatukan dengan beton (untuk tulangan tipis).", _origIndex: 189 },
  { id: 200, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "かたわくこうじしほこう", jp: "型枠工事・支保工（かたわく・しほこう）", id_text: "Pekerjaan bekisting dan penopangnya", desc: "Cetakan kayu (型枠) melingkupi tulangan, beton dicor, diperkuat pipa baja luar (支保工). Setelah mengeras, dibongkar dan dipakai ulang. Mandor:「型枠の締め付け確認して」(cek pengencangan bekisting).", _origIndex: 191 },
  { id: 201, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "れぢみくすどこんくりいとなまこんあっそう", jp: "レディミクスドコンクリート（生コン）", id_text: "Ready-mix concrete dan pemompaan beton", desc: "Beton berkualitas dari pabrik (生コン) dikirim truk molen (トラックアジテータ), lalu dipompa ke bekisting. Mandor:「生コン到着したら圧送開始して」(beton datang, mulai pompa).", _origIndex: 192 },
  { id: 203, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "さかんこうじかべつちしっくいもるたる", jp: "左官工事（さかん）", id_text: "Pekerjaan plesteran tradisional Jepang", desc: "Gunakan kote (roskam) untuk oleskan 壁土, 漆喰 (kapur), atau モルタル ke dinding/lantai. Berbeda dari painting (塗装). Mandor:「左官さん、仕上げはいつですか」(kapan finishing plester).", _origIndex: 194 },
  { id: 204, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ぼうすいこうじしゅるい", jp: "防水工事の5種類", id_text: "5 jenis pekerjaan waterproofing", desc: "①ウレタン=cairan, cocok area rumit. ②FRP=serat kaca+resin. ③シート=lembaran karet. ④アスファルト=tempel lembaran aspal. ⑤シーリング=sealant isi celah. Mandor:「プライマー塗ってから施工して」(oleskan primer dulu).", _origIndex: 195 },
  { id: 205, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "みやだいく", jp: "宮大工（みやだいく）", id_text: "Tukang kayu kuil & shrine tradisional", desc: "Spesialis bangun/renovasi kuil (お寺) dan shrine (神社). Butuh ilmu jenis kayu dan sambungan kayu agar tahan ratusan tahun. Mandor:「仕口の加工、寸法確認して」(cek ukuran sambungan kayu).", _origIndex: 196 },
  { id: 206, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "あまじまい", jp: "雨仕舞（あまじまい）", id_text: "Penanganan air hujan / rain detailing", desc: "Pengetahuan dan teknik konstruksi untuk mencegah air hujan masuk ke dalam bangunan melalui atap dan sambungan material. Merupakan kompetensi wajib dalam pekerjaan atap (屋根工事) dan panel baja (建築板金工事).", _origIndex: 197 },
  { id: 212, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "とそうこうじほうほうはけろおらあえあすぷれえ", jp: "塗装工事の3方法（はけ・ローラー・エアスプレー）", id_text: "3 metode cat: kuas / roller / semprotan", desc: "①はけ塗り=kuas, cocok bentuk apapun, hasil rapi. ②ローラー=efisien area luas. ③エアスプレー=cat dikabut kompresor, untuk area luas/sulit. Mandor:「外壁はローラーで仕上げて」(dinding luar pakai roller).", _origIndex: 203 },
  { id: 213, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ぞおえんこうじしゅるい", jp: "造園工事の5種類", id_text: "5 jenis pekerjaan taman/lansekap", desc: "①植栽=tanam pohon. ②屋上緑化=hijau atap/dinding gedung. ③広場=lapangan. ④公園設備=gazebo, air mancur. ⑤緑地育成=perbaikan tanah+penyangga pohon. Mandor:「植栽の配置図確認して」(cek layout tanam pohon).", _origIndex: 204 },
  { id: 214, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "けいてんこうじぼおどはりくろすはり", jp: "軽天工事（けいてん）・LGS", id_text: "Pekerjaan rangka LGS + papan gypsum + wallpaper", desc: "LGS (Light Gauge Steel/スタッド) untuk rangka dinding/plafon (軽天工事). Di atasnya papan gypsum (ボード貼り), sambungan dirapikan pate, lalu wallpaper (クロス貼り). Mandor:「LGSのピッチ確認して」(cek jarak rangka LGS).", _origIndex: 205 },
  { id: 215, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "かばあこうほうさしかいしゅう", jp: "カバー工法（サッシ改修）", id_text: "Renovasi kusen tanpa bongkar rangka lama", desc: "カバー工法=pasang rangka baru DI ATAS rangka lama tanpa bongkar, lalu pasang sash baru. Hemat vs ganti total. Mandor:「カバー工法で行きましょう」(pakai metode cover saja).", _origIndex: 206 },
  { id: 217, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "いしこうじだいりいしみかげいしぎいし", jp: "石工事", id_text: "Pekerjaan batu: marmer, granit, batu artifisial", desc: "大理石=marmer, 御影石=granit, 擬石=batu tiruan dipasang ke bangunan (estetika, bukan struktur). Batu yang retak saat proses tidak bisa dipakai. Mandor:「大理石、割れないよう慎重に」(hati-hati jangan sampai marmer retak).", _origIndex: 208 },
  { id: 236, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "こんくりいとあっそうこうじやくちいむわあく", jp: "コンクリート圧送工事の3役チームワーク", id_text: "3 peran tim pengecoran: pompa/selang/pemadatan", desc: "①操作オペレータ=operasikan pompa. ②筒先作業員=arahkan ujung selang ke bekisting. ③土工作業員=operasikan バイブレータ (締固め). Harus sinkron karena 生コン mulai mengeras. Mandor:「3人ちゃんと連携してくれ」(3 orang harus sinkron).", _origIndex: 227 },
  { id: 237, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "さかんしあげとぎだしあらいだし", jp: "左官仕上げ", id_text: "Finishing plester: poles batu vs cuci permukaan", desc: "研ぎ出し=permukaan dipoles hingga rata mengkilap. 洗い出し=batu hias (種石) dicampur semen, ditempel, dicuci sikat agar batu menonjol. Butuh teknik tinggi. Mandor:「洗い出し仕上げ、丁寧にやって」(cuci permukaan teliti).", _origIndex: 228 },
  { id: 238, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "ざいらいじくぐみこうほうもくぞうじゅうたく", jp: "在来軸組工法（ざいらいじくぐみ）", id_text: "Rangka kayu tradisional Jepang — metode dominan", desc: "Metode kayu paling umum di Jepang: kolom (柱) dan balok (梁) dirakit sebagai rangka struktural. 工務店 tangani semua: desain, kayu, konstruksi. Mandor:「柱と梁の接合部確認して」(cek sambungan kolom-balok).", _origIndex: 229 },
  { id: 240, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "たてぐのざいりょうしゅるいしゃったあじどうどあ", jp: "建具の材料種類 + シャッター・自動ドア", id_text: "Material kusen/pintu + shutter & pintu otomatis", desc: "建具=semua pemasangan di bukaan (pintu, jendela, fusuma, shoji). Material: 木製・アルミ・樹脂・鋼・ステンレス. Termasuk シャッター dan 自動ドア取付工事. Mandor:「建具の建て付け調整して」(sesuaikan pasang kusen/pintu).", _origIndex: 231 },
  { id: 248, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ふきつけうれたんせこうまえけんさっいたせこうちゅうかくにんかんかく", jp: "吹付けウレタン", id_text: "QC uretan semprot: uji papan + ukur ketebalan", desc: "Sebelum施工: semprotkan ke papan 450mm×450mm, cek kepadatan busa. Selama施工: tiap 4〜5m ukur ketebalan. Permukaan beton wajib bersih. Mandor:「施工前確認板、見せて」(tunjukkan papan uji).", _origIndex: 239 },
  { id: 249, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "こんくりいとぶろっくぞうぞうてっきんもるたるほきょう", jp: "コンクリートブロック造（CB造）", id_text: "Blok beton: tulangan di rongga + mortar penguat", desc: "Blok beton berlubang disusun. Rongga diisi tulangan baja lalu dicor mortar, lebih kokoh dari bata. Untuk pagar, tembok penahan, bangunan kecil. Mandor:「ブロックの通り確認して」(cek kesejajaran blok).", _origIndex: 240 },
  { id: 260, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "のりめんじやまやまがくるやまどめ", jp: "法面・地山・山がくる・山留め", id_text: "Lereng galian / tanah alami / longsor / penahan", desc: "法面=permukaan miring galian. 地山=tanah kondisi alami. 山がくる=lereng LONGSOR — BAHAYA! 山留め=menahan tanah agar tidak runtuh. Mandor:「山留めが変形したらすぐ報告して」.", _origIndex: 251 },
  { id: 264, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "きそめんしん", jp: "基礎免振（きそめんしん）", id_text: "Isolasi seismik pada pondasi", desc: "Sistem yang menyerap gaya horizontal gempa sehingga getaran berkurang sebelum masuk bangunan. Dipasang antara tanah dan pondasi. Mandor:「免振の点検は専門業者に任せてくれよ」.", _origIndex: 255 },
  { id: 267, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "はいきんかんかくあき", jp: "配筋・間隔（かんかく）・あき", id_text: "Pemasangan tulangan / jarak as-as / jarak bersih", desc: "配筋=mengatur dan merakit besi tulangan. 間隔=jarak center-to-center. あき=jarak BERSIH antar tulangan. Wajib dipenuhi sesuai standar. Mandor:「あきと間隔を図面通りに確認して」.", _origIndex: 258 },
  { id: 268, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "かぶりあつさ", jp: "かぶり厚さ", id_text: "Selimut beton (jarak tulangan ke permukaan beton)", desc: "Jarak antara permukaan LUAR besi tulangan ke permukaan beton yang menutupinya. Harus cukup tebal untuk melindungi tulangan dari korosi dan api. Termasuk hal yang selalu dicek dalam inspeksi kualitas.", _origIndex: 259 },
  { id: 279, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "ぞうぞうぞうもくぞう", jp: "RC造・S造・SRC造・木造", id_text: "RC / S / SRC / kayu — 4 jenis struktur bangunan", desc: "RC造=beton bertulang. S造=baja. SRC造=baja+beton bertulang. 木造=kayu. Wajib dikenali untuk identifikasi pekerjaan SSW. Mandor:「この現場はRC造だから配筋が重要だ」.", _origIndex: 270 },
  { id: 305, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "あそびたてかみ", jp: "あそび・建込み（たてこみ）", id_text: "Kelonggaran sambungan / mendirikan bekisting tegak", desc: "あそび=kelonggaran yang disengaja agar sambungan tidak terlalu kencang. 建込み=mendirikan bekisting sesuai garis 墨出し dan dikunci pada posisi. Mandor:「建込みは墨に合わせてあそびを確認してくれ」.", _origIndex: 296 },
  { id: 322, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "こんくりいとぶろっくぞう", jp: "コンクリートブロック造（ぞう）", id_text: "Struktur bata/blok beton yang ditumpuk", desc: "Jenis struktur menggunakan blok beton yang ditumpuk. Dipakai untuk pagar, dinding pembatas, dan bangunan kecil. Berbeda dari RC造 yang dicor monolit. Mandor:「ブロック積みは目地を一直線にそろえてくれよ」.", _origIndex: 313 },
  { id: 635, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "けんちくぶつのこうぞうごしゅるい", jp: "建築物の構造5種類", id_text: "5 jenis struktur bangunan dan karakteristiknya", desc: "RC造=tulangan+beton. S造=baja, untuk pabrik/komersial. SRC造=baja+RC, gedung tinggi. 木造=kayu, rumah biasa. CB造=blok beton+tulangan+mortar. Mandor:「ここはRC造、型枠と鉄筋の確認して」(cek bekisting dan tulangan RC).", _origIndex: 626 },
  { id: 636, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "けんちくこうじのながれだいきぼびる", jp: "建築工事の流れ（大規模ビル・マンション）", id_text: "Urutan tahapan konstruksi gedung besar", desc: "①準備: pagar+borlog ②山留め: dinding cegah longsor ③杭: pancang ke支持層 ④土工: gali+残土 ⑤地下躯体: tulangan+cor ⑥地上躯体: baja+crane ⑦仕上げ: finishing. Mandor:「次は山留め確認からだ」(cek dinding penahan dulu).", _origIndex: 627 },
  { id: 637, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "たいしんせいしんめんしんのさんしゅるい", jp: "耐震・制振・免振の3種類（地震対策）", id_text: "3 metode proteksi gempa: tahan/redam/isolasi", desc: "①耐震=perkuat kolom & balok. ②制振=pasang ダンパー kurangi goyangan. ③免振=pasang アイソレータ di fondasi, isolasi energi gempa. 震度5強=berfungsi, 6強〜7=tidak runtuh. Mandor:「免振装置の点検記録見せて」(tunjukkan catatan isolator).", _origIndex: 628 },
  { id: 642, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "てっきんひつぎてのよんしゅるい", jp: "鉄筋継手の4種類", id_text: "4 jenis sambungan besi tulangan", desc: "4 sambungan tulangan: ①ガス圧接=panas+tekan (paling umum). ②溶接=las busur. ③機械式=besi berulir+coupler. ④重ね=tumpuk besi tipis, disatukan beton. Mandor:「ガス圧接の外観確認して」(cek visual sambungan).", _origIndex: 633 },
  { id: 644, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "かたわくこうじとしほこうかたわくだいく", jp: "型枠工事と支保工（かたわく大工）", id_text: "Pekerjaan bekisting & perancah penopang beton cor", desc: "Cetakan kayu dibuat 型枠大工. Beton cair masuk: tekanan besar → perkuat 支保工 (pipa besi luar). Baca 加工図 dulu. Setelah mengeras, cetakan dibongkar, dipakai ulang. Mandor:「支保工の本数、図面通り確認して」(cek jumlah strut).", _origIndex: 635 },
  { id: 645, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "こんくりいとあっそうこうじとさんしゃちいむわあく", jp: "コンクリート圧送工事と3者チームワーク", id_text: "Pengecoran beton dengan pompa: 3 peran sinkron", desc: "生コン dari pabrik → truk アジテータ → コンクリートポンプ車. 3 peran sinkron: ①オペレータ(pompa) ②筒先(selang) ③土工(締固めvibrator). Beton mengeras cepat, wajib koordinasi. Mandor:「3人連携、タイムロスなしで」(3 orang sinkron, tanpa tunda).", _origIndex: 636 },
  { id: 647, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "さかんこうじととくしゅしあげとぎだしあらいだししっくい", jp: "左官工事（研ぎ出し・洗い出し・漆喰）", id_text: "Pekerjaan plester dinding + 2 teknik finishing", desc: "左官工事=oles 壁土/モルタル/漆喰 pakai こて. ①研ぎ出し=asah permukaan batu hingga mengkilap. ②洗い出し=種石+semen, sikat permukaan agar batu menonjol. Mandor:「漆喰の養生期間守ってください」(patuhi waktu pengeringan漆喰).", _origIndex: 638 },
  { id: 648, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ふきつけうれたんだんねつこうじにせいぶん", jp: "吹付けウレタン断熱工事", id_text: "Insulasi semprot uretan keras: 2 komponen + QC", desc: "Semprot 硬質ウレタンフォーム ke bangunan. Bahan: ①ポリオール成分 + ②ポリイソシアネート. QC: sebelum=uji papan 450mm正方形, cek密度. Selama=cek ketebalan tiap 4〜5m. Mandor:「施工前確認板、見せてください」(tunjukkan papan uji dulu).", _origIndex: 639 },
  { id: 650, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ないそうしあげこうじぼおどくろすゆかかあてん", jp: "内装仕上げ工事（LGS・ボード・クロス・床）", id_text: "Finishing interior: LGS hingga wallpaper & lantai", desc: "①LGS/軽天=rangka baja ringan. ②ボード=papan gypsum+pate. ③クロス=wallpaper. ④塗装仕上げ=cat pengganti wallpaper. ⑤床仕上げ=ubin/karpet. ⑥カーテン工事=pasang tirai. Mandor:「LGSのピッチ、設計通りか確認して」(cek jarak LGS sesuai desain).", _origIndex: 641 },
  { id: 651, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "さっしこうじとかばあこうほうきんぞくたてぐ", jp: "サッシ工事とカバー工法（金属建具の取付け）", id_text: "Pekerjaan sash logam + renovasi kusen metode cover", desc: "サッシ工事=pasang kusen logam: jendela aluminium, pintu, kasa nyamuk. Renovasi: カバー工法=pasang kusen baru DI ATAS lama tanpa bongkar → hemat biaya & waktu. Mandor:「カバー工法で対応します」(tangani dengan metode cover).", _origIndex: 642 },
  { id: 657, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "けんちくだいくこうじのしゅるいまちぞうさくみや", jp: "建築大工工事の種類（町大工・造作大工・宮大工）", id_text: "Jenis tukang kayu: rumah / finishing / kuil", desc: "①町大工=tukang kayu rumah tinggal biasa (paling umum). ②造作大工=pasang pintu, 障子, ふすま, interior. ③宮大工=kuil/shrine, teknik sambungan kayu tertinggi. Mandor:「造作大工さん、建具の取付お願いします」(pasang pintu/kusen).", _origIndex: 648 },
  { id: 658, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "やねこうじかわらぶきあまじまいごしゅるい", jp: "屋根工事：瓦ぶきと雨仕舞い + 5種の屋根工事", id_text: "Pekerjaan atap: genteng, drainase hujan, 5 jenis", desc: "瓦=genteng tanah liat dibakar. 雨仕舞い=sistem alirkan air hujan, wajib dikuasai. 5 jenis: ふき替え, 重ねぶき, 漆喰補修, 雨どい交換, 屋根塗装. Mandor:「雨仕舞いの施工確認して、漏れないように」(cek sistem drainase, jangan bocor).", _origIndex: 649 },
  { id: 660, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "いしこうじいしくだいりせきみかげいしぎいせき", jp: "石工事（石工・大理石・御影石・擬石）", id_text: "Pekerjaan batu: pasang batu alam/buatan", desc: "大理石(marmer), 御影石(granit), 擬石(tiruan) dipasang untuk estetika bukan struktur. Batu mahal → tidak boleh gagal. 乱形石 butuh pengalaman panjang. Mandor:「大理石、慎重に加工して」(proses marmer hati-hati).", _origIndex: 651 },
  { id: 669, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "かべしいんはしらしいんおやずみかねをふるすみつけ", jp: "壁芯・柱芯・親墨・矩を振る・墨付け", id_text: "5 istilah sumidashi — garis tengah & referensi", desc: "壁芯=garis tengah dinding. 柱芯=garis tengah kolom. 親墨=referensi untuk 墨出し berikutnya. 矩を振る=tarik garis sudut 90°. 墨付け=tanda pengerjaan pada kayu. Mandor:「壁芯と柱芯がずれていないか確認してくれ」.", _origIndex: 660 },
  { id: 675, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "どどめようへきやいたこうやいたやまどめ", jp: "土留め・擁壁・矢板・鋼矢板・山留め（崩壊防止5語）", id_text: "5 istilah penahan tanah & pencegah longsor galian", desc: "土留め=menahan tanah agar tidak longsor. 擁壁=土留め berbentuk dinding. 矢板=papan penahan tanah. 鋼矢板=矢板 baja saling menyambung. 山留め=menahan tanah dengan 矢板. Mandor:「山留めの変形があれば報告して」.", _origIndex: 666 },
  { id: 678, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "じやまのりめんやまがくる", jp: "地山・法面・山がくる（自然地盤と崩壊危険）", id_text: "3 istilah tanah alami & bahaya lereng galian", desc: "地山=tanah dalam kondisi alami. 法面(のり)=permukaan miring pada galian. 山がくる=turap atau lereng RUNTUH/LONGSOR — sering jadi kecelakaan serius. Mandor:「法面が崩れそうなら作業を止めて報告してくれ」.", _origIndex: 669 },
  { id: 681, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "くいきそすらぶくいじぎょうきそめんしん", jp: "杭基礎・スラブ・杭地業・基礎免振", id_text: "4 istilah pondasi tiang, slab & isolasi gempa", desc: "杭基礎=pondasi tiang untuk tanah lemah. スラブ=bagian datar bangunan. 杭地業=pekerjaan tiang pondasi. 基礎免振=sistem serap gaya gempa antara tanah dan pondasi. Mandor:「杭の打設記録を毎本記録してくれよ」.", _origIndex: 672 },
  { id: 683, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "はいきんひろいだしあそびあきかんかく", jp: "配筋・拾い出し・あそび・あき・間隔（鉄筋基本5語）", id_text: "5 istilah dasar pemasangan & perhitungan besi", desc: "配筋=tempatkan dan rakit besi tulangan. 拾い出し=hitung kebutuhan material dari gambar. あそび=toleransi. あき=jarak bersih antar tulangan. 間隔=jarak center-to-center. Mandor:「あきと間隔は設計図通りかチェックして」.", _origIndex: 674 },
  { id: 684, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "すてっこんけっそくかぶりあつさ", jp: "捨てコン・結束（ハッカー）・かぶり厚さ", id_text: "3 istilah presisi konstruksi beton bertulang", desc: "捨てコン=cor beton tipis 5–10cm sebagai referensi ketinggian. 結束=ikat persilangan tulangan dengan 結束線 pakai ハッカー. かぶり厚さ=jarak tulangan ke permukaan beton. Mandor:「かぶり厚さが設計値を満たしているか確認してくれ」.", _origIndex: 675 },
  { id: 685, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "たてこみのろあんこてんようぱんくくぎじまい", jp: "建込み・ノロ・アンコ・転用・パンク・釘仕舞", id_text: "6 istilah pekerjaan bekisting", desc: "建込み=dirikan bekisting. ノロ=bocoran beton dari sambungan. アンコ=pengisi agar beton tidak masuk ke alur. 転用=pakai ulang bekisting. パンク=bekisting jebol. 釘仕舞=cabut paku bekas. Mandor:「パンクしないよう支保工をしっかりしてくれよ」.", _origIndex: 676 },
  { id: 693, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "ぞうぞうぞうもくぞうぞう", jp: "RC造・S造・SRC造・木造・CB造", id_text: "5 singkatan struktur bangunan — definisi akronim", desc: "RC造=鉄筋コンクリート. S造=鉄骨. SRC造=鉄骨鉄筋コンクリート. 木造=kayu. CB造=blok beton ditumpuk. Mandor:「この現場はSRC造だから、鉄骨と配筋の両方が重要だ」.", _origIndex: 684 },
  { id: 711, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "どうろこうじ", jp: "道路工事", id_text: "Pekerjaan jalan", desc: "Membuat/memperbaiki jalan. Meliputi: aspal, rambu (標識), lampu lalu lintas, trotoar, marka, lanskap. Lebih banyak perbaikan jalan lama. Mandor:「舗装の厚さ、規定通りか確認して」(cek ketebalan aspal sesuai spec).", _origIndex: 702 },
  { id: 713, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ひょうそうこうじ", jp: "表装工事（ひょうそうこうじ）", id_text: "Pekerjaan pelapis permukaan interior", desc: "Bagian 内装仕上げ工事, TIDAK termasuk LGS. Jenis: ①壁仕上げ (wallpaper/クロス). ②天井仕上げ (langit-langit, sulit). ③床仕上げ (ubin/karpet/tatami). ④塗装仕上げ. ⑤カーテン工事. Mandor:「クロス張りの前にパテ処理して」(dempul dulu sebelum wallpaper).", _origIndex: 704 },
  { id: 747, category: "kenchiku_kutai", source: "jac-gakka1", type: "konsep", furi: "てっこつこうじ", jp: "鉄骨工事（てっこつこうじ）", id_text: "Pekerjaan struktur baja (steel frame)", desc: "Membangun rangka bangunan menggunakan baja: kolom (柱), balok (梁), dan elemen diagonal. Struktur baja: ブレース, ラーメン構造, トラス. Berbeda dari 鉄筋工事 (tulangan beton).", _origIndex: 738 },
  { id: 748, category: "kenchiku_kutai", source: "jac-gakka1", type: "konsep", furi: "こんくりいとだせつこうじ", jp: "コンクリート打設工事（コンクリートだせつこうじ）", id_text: "Pekerjaan pengecoran beton", desc: "Menuangkan beton cair (生コン) ke dalam bekisting (型枠). Alur: muat → pompa → tuang → padatkan (バイブレータ) → finishing. Tim 3 peran: 筒先, 振動機操作, 補助. Mandor:「バイブレータでしっかり締め固めて」(padatkan beton pakai vibrator).", _origIndex: 739 },
  { id: 749, category: "kenchiku_shiage", source: "jac-gakka2", type: "konsep", furi: "くたい", jp: "躯体（くたい）", id_text: "Struktur utama bangunan", desc: "Bagian struktural bangunan: 基礎 (pondasi) + 柱 (kolom) + 梁 (balok) + 壁面 (dinding) + 床 (lantai). = tulang/kerangka utama. BUKAN: 内装仕上げ (finishing dalam), 建具 (kusen pintu/jendela), 屋根 (atap).", _origIndex: 740 },
  { id: 1251, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "あーすあんかー", jp: "アースアンカー", id_text: "Angkur tanah / ground anchor", desc: "例: 急傾斜地の擁壁にはアースアンカーを使って引張力を確保する。→ Pada dinding penahan di lereng curam, earth anchor digunakan untuk menahan gaya tarik. Kabel atau batang baja ditanam ke tanah keras.", _origIndex: 1229 },
  { id: 1254, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "とまくぼうすい", jp: "塗膜防水", id_text: "Waterproofing lapisan coating", desc: "例: 塗膜防水はウレタン系材料をローラーで塗布して防水層を形成する。→ Coating waterproofing membentuk lapisan kedap air dengan cara mengoleskan material uretan menggunakan roller. Cocok untuk bentuk permukaan tidak beraturan.", _origIndex: 1232 },
  { id: 1258, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "すぺーさー", jp: "スペーサー", id_text: "Penyangga tulangan / beton tahu", desc: "例: スペーサーはかぶり厚さを一定に保つために鉄筋の下に置く。→ Spacer (beton tahu) diletakkan di bawah tulangan untuk menjaga ketebalan selimut beton tetap sesuai standar. Terbuat dari mortar atau plastik.", _origIndex: 1236 },
  { id: 1260, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "せぱれーたー", jp: "セパレーター", id_text: "Pengikat jarak bekisting (form tie)", desc: "例: セパレーターは両側の型枠を一定間隔に保持する金属製スペーサーである。→ Separator adalah pengikat logam yang menjaga jarak antar dua sisi bekisting agar tetap konsisten saat pengecoran beton.", _origIndex: 1238 },
  { id: 1261, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "かたわくりけいざい", jp: "型枠離型剤", id_text: "Minyak/agen pelepas bekisting", desc: "例: 型枠離型剤を塗布することで、脱型時にコンクリートが型枠に張り付くのを防ぐ。→ Release agent (離型剤) dioleskan ke permukaan bekisting sebelum pengecoran agar mudah dilepas setelah beton mengeras.", _origIndex: 1239 },
  { id: 1264, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "じゃんか", jp: "ジャンカ", id_text: "Sarang lebah / cacat beton keropos", desc: "例: 締固め不足や生コンの分離によってジャンカが発生する。→ Janka (honeycomb) adalah cacat pada beton dimana terdapat rongga-rongga yang terlihat di permukaan, akibat pemadatan yang kurang atau beton terlalu encer.", _origIndex: 1242 },
  { id: 1266, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "てっきんたんさき", jp: "鉄筋探査機", id_text: "Alat deteksi/pencari tulangan beton", desc: "例: 鉄筋探査機（電磁波レーダー）でコンクリート内部の鉄筋位置を確認する。→ Rebar detector menggunakan gelombang elektromagnetik untuk mendeteksi posisi dan kedalaman tulangan di dalam beton tanpa merusaknya.", _origIndex: 1244 },
  { id: 1267, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "べーすぷれーと", jp: "ベースプレート", id_text: "Pelat dasar kolom baja", desc: "例: 鉄骨柱の下部にベースプレートを設け、アンカーボルトで基礎と固定する。→ Base plate adalah pelat baja yang dipasang di bawah kolom baja, disambungkan ke pondasi beton menggunakan anchor bolt untuk menyalurkan beban.", _origIndex: 1245 },
  { id: 1271, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "あんかーぼると", jp: "アンカーボルト", id_text: "Baut angkur / anchor bolt", desc: "例: アンカーボルトはベースプレートと基礎コンクリートを緊結する締結部材である。→ Anchor bolt adalah baut yang ditanam di pondasi beton untuk mengikat base plate kolom baja.", _origIndex: 1249 },
  { id: 1273, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "けいりょうてっこつしたじ", jp: "軽量鉄骨下地", id_text: "Rangka baja ringan (LGS) untuk dinding/plafon", desc: "例: 軽量鉄骨下地にビスで石膏ボードを留めて壁を仕上げる。→ Papan gipsum disekrup ke rangka baja ringan untuk membentuk dinding finishing. Rangka ini disusun dari ランナー (runner) dan スタッド (stud).", _origIndex: 1251 },
  { id: 1274, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "てんじょうしたじ", jp: "天井下地", id_text: "Rangka substrat plafon", desc: "例: 天井下地は野縁受けと野縁で構成され、その上に石膏ボードを張る。→ Rangka plafon terdiri dari penggantung (野縁受け) dan besi furring (野縁), lalu papan gipsum dipasang di atasnya sebagai penutup plafon.", _origIndex: 1252 },
  { id: 1287, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "ふきつけとそう", jp: "吹付け塗装", id_text: "Pengecatan semprot / spray painting", desc: "例: 吹付け塗装はエアスプレーで塗料を霧状に吹き付け、広い面積を均一に仕上げる工法だ。→ Pengecatan semprot menggunakan semprotan udara bertekanan untuk menghasilkan lapisan cat yang merata di area luas seperti dinding beton dan fasad bangunan.", _origIndex: 1265 },
  { id: 1290, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "したじしょり", jp: "下地処理", id_text: "Persiapan substrat / surface preparation", desc: "例: 塗装工事の前に下地処理として汚れ・旧塗膜・錆を除去して素地を整える。→ Sebelum pengecatan atau pemasangan finishing, substrat dibersihkan dari kotoran, cat lama, dan karat. Kualitas下地処理 menentukan daya tahan lapisan finishing.", _origIndex: 1268 },
  { id: 1291, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "かべクロス", jp: "壁クロス", id_text: "Wallcovering vinil / wallpaper dinding", desc: "例: 壁クロスは下地ボードにのりで貼り付ける内装仕上げの最終工程だ。→ Wallpaper vinil (壁クロス) ditempel pada papan gipsum menggunakan lem sebagai tahap akhir finishing interior. Jenis paling umum adalah ビニルクロス (vinyl cloth).", _origIndex: 1269 },
  { id: 1293, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "ランナー", jp: "ランナー", id_text: "Runner / rel horizontal LGS di lantai dan plafon", desc: "例: ランナーは床と天井にアンカーで固定され、スタッドを保持するU形の鋼材だ。→ Runner adalah profil baja berbentuk U yang dipasang di lantai dan plafon menggunakan anchor, berfungsi sebagai landasan dan penahan untuk stud pada sistem", _origIndex: 1271 },
  { id: 1295, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "ふねんざいりょう", jp: "不燃材料", id_text: "Material tidak dapat terbakar (non-combustible)", desc: "例: 石膏ボードやALCパネルは建築基準法で不燃材料として認定されている。→ Papan gipsum dan panel ALC diakui sebagai材料 tidak dapat terbakar (不燃材料) berdasarkan Undang-Undang Standar Bangunan Jepang.", _origIndex: 1273 },
  { id: 1296, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "せっちゃくこうほう", jp: "接着工法", id_text: "Metode pemasangan adhesif (tile/board)", desc: "例: 内装タイルの接着工法では有機系接着剤を下地に塗布してタイルを張り付ける。→ Pada metode adhesif untuk tile interior, lem organik dioleskan ke substrat kemudian tile ditempel langsung.", _origIndex: 1274 }
];
